#include <stdio.h>
#include <math.h>
long long gcd(long long a, long long b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}
long long phi(long long n) {
    long long result = n;
    for (long long i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            while (n % i == 0)
                n /= i;
            result -= result / i;
        }
    }
    if (n > 1)
        result -= result / n;
    return result;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long L, R;
        scanf("%lld %lld", &L, &R);
        long long count = 0;
        for (long long i = L; i <= R; i++) {
            if (i % phi(i) == 0)
                count++;
        }
        printf("%lld\n", count);
    }
    return 0;
}

