    for (let i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            while (n % i == 0)
                n = Math.floor(n / i);
            result -= Math.floor(result / i);
        }
    }
    if (n > 1)
        result -= Math.floor(result / n);
